```typescript
async restoreStock(orderId: string): Promise<void> {
  // Récupérer la commande avec ses items
  const order = await this.orderRepository.findOne({
    where: { id: orderId },
    relations: ['items', 'items.productVariant']
  });

  if (!order) throw new NotFoundException('Commande introuvable');

  // Pour chaque item, restaurer le stock
  for (const item of order.items) {
    const variant = item.productVariant;
    if (variant) {
      variant.stock += item.quantity;
      await this.productVariantRepository.save(variant);

      // Optionnel : logger la restauration
      this.logger.log(`Stock restauré pour ${variant.sku}: +${item.quantity}`);
    }
  }

  // Mettre à jour le statut de la commande
  order.status = 'cancelled';
  await this.orderRepository.save(order);
}
