```typescript
async cancelOrder(orderId: string, userId: string): Promise<Order> {
  const order = await this.orderRepository.findOne({
    where: { id: orderId, user: { id: userId } },
    relations: ['items']
  });

  if (!order) throw new NotFoundException('Commande introuvable');

  // Vérifier les conditions d'annulation
  const cancellableStatuses = ['pending', 'paid'];
  if (!cancellableStatuses.includes(order.status)) {
    throw new BadRequestException(
      `Impossible d'annuler la commande : statut actuel "${order.status}". Seules les commandes en attente ou payées non expédiées peuvent être annulées.`
    );
  }

  // Vérifier que la commande n'est pas déjà expédiée (par sécurité)
  if (order.shippedAt && order.shippedAt <= new Date()) {
    throw new BadRequestException('Commande déjà expédiée, annulation impossible');
  }

  // Procéder à l'annulation
  await this.restoreStock(orderId);
  order.status = 'cancelled';
  order.cancelledAt = new Date();

  return this.orderRepository.save(order);
}
