```typescript
async getAverageDeliveryDays(startDate: Date, endDate: Date): Promise<number> {
  // Récupérer toutes les commandes livrées dans la période
  const orders = await this.orderRepository
    .createQueryBuilder('order')
    .where('order.status = :status', { status: 'delivered' })
    .andWhere('order.deliveredAt BETWEEN :startDate AND :endDate', { startDate, endDate })
    .getMany();

  if (orders.length === 0) return 0;

  let totalDays = 0;
  for (const order of orders) {
    // Le statut 'paid' a été enregistré dans la timeline
    const paidEntry = await this.statusHistoryRepository.findOne({
      where: { order: { id: order.id }, status: 'paid' }
    });

    if (paidEntry && order.deliveredAt) {
      const diffTime = Math.abs(order.deliveredAt.getTime() - paidEntry.changedAt.getTime());
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
      totalDays += diffDays;
    }
  }

  const average = totalDays / orders.length;
  return parseFloat(average.toFixed(2));
}
```

Alternative avec une requête SQL brute plus performante :
```sql
SELECT AVG(EXTRACT(DAY FROM (o.delivered_at - h.changed_at))) as avg_delivery_days
FROM orders o
JOIN order_status_history h ON h.order_id = o.id AND h.status = 'paid'
WHERE o.status = 'delivered' 
  AND o.delivered_at BETWEEN $1 AND $2;
```
